        QCOMPARE(*property->offset(), *OffsetPropertyGroup::empty());
        QCOMPARE(property->color().value(), emptyValue<Union::Color>());
        QCOMPARE(property->size().value(), emptyValue<qreal>());
        QCOMPARE(property->blur().value(), emptyValue<qreal>());
